import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");

const transferSource = join(
  root,
  "circuits/veil_shield_transfer/target/VeilShieldTransferVerifier.sol"
);
const withdrawSource = join(
  root,
  "circuits/veil_shield_withdraw/target/VeilShieldWithdrawVerifier.sol"
);
const outputDir = join(root, "contracts/src/verifiers");

const GENERATED_NOTICE =
  "// Generated by scripts/generate-veilshield-verifiers.mjs from Barretenberg Solidity verifier output.\n" +
  "// Do not edit by hand; regenerate after changing Noir circuits or bb versions.\n\n";

function readGenerated(path) {
  return readFileSync(path, "utf8");
}

function extractConstant(source, name) {
  const match = source.match(new RegExp(`uint256 constant ${name} = ([^;]+);`));
  if (!match) throw new Error(`Missing ${name} in generated verifier`);
  return match[1].trim();
}

function extractKeyLibrary(source, libraryName) {
  const start = source.indexOf("library HonkVerificationKey");
  const end = source.indexOf("pragma solidity ^0.8.27;");
  if (start === -1 || end === -1 || end <= start) {
    throw new Error("Unable to extract Barretenberg verification key library");
  }

  return source
    .slice(start, end)
    .trim()
    .replace("library HonkVerificationKey", `library ${libraryName}`);
}

function cleanSolidity(source) {
  return source
    .split("\n")
    .map((line) => line.trimEnd())
    .join("\n");
}

function writeBase(source) {
  const start = source.indexOf("interface IVerifier");
  const end = source.indexOf("contract HonkVerifier");
  if (start === -1 || end === -1 || end <= start) {
    throw new Error("Unable to extract Barretenberg verifier base");
  }

  const body = source.slice(start, end).trim();
  const output = [
    "// SPDX-License-Identifier: Apache-2.0",
    GENERATED_NOTICE.trimEnd(),
    "pragma solidity ^0.8.27;",
    "",
    body,
    "",
  ].join("\n");

  writeFileSync(join(outputDir, "BaseZKHonkVerifier.sol"), cleanSolidity(output));
}

function writeConcreteVerifier({ source, contractName, keyLibraryName, prefix }) {
  const keyLibrary = extractKeyLibrary(source, keyLibraryName);
  const n = extractConstant(source, "N");
  const logN = extractConstant(source, "LOG_N");
  const publicInputs = extractConstant(source, "NUMBER_OF_PUBLIC_INPUTS");
  const vkHash = extractConstant(source, "VK_HASH");

  const output = [
    "// SPDX-License-Identifier: Apache-2.0",
    GENERATED_NOTICE.trimEnd(),
    "pragma solidity ^0.8.27;",
    "",
    'import {BaseZKHonkVerifier, Honk} from "./BaseZKHonkVerifier.sol";',
    "",
    `uint256 constant ${prefix}_N = ${n};`,
    `uint256 constant ${prefix}_LOG_N = ${logN};`,
    `uint256 constant ${prefix}_NUMBER_OF_PUBLIC_INPUTS = ${publicInputs};`,
    `uint256 constant ${prefix}_VK_HASH = ${vkHash};`,
    "",
    keyLibrary,
    "",
    `contract ${contractName} is BaseZKHonkVerifier(${prefix}_N, ${prefix}_LOG_N, ${prefix}_VK_HASH, ${prefix}_NUMBER_OF_PUBLIC_INPUTS) {`,
    "    function loadVerificationKey() internal pure override returns (Honk.VerificationKey memory) {",
    `        return ${keyLibraryName}.loadVerificationKey();`,
    "    }",
    "}",
    "",
  ].join("\n");

  writeFileSync(join(outputDir, `${contractName}.sol`), cleanSolidity(output));
}

mkdirSync(outputDir, { recursive: true });

const transfer = readGenerated(transferSource);
const withdraw = readGenerated(withdrawSource);

writeBase(transfer);
writeConcreteVerifier({
  source: transfer,
  contractName: "TransferVerifier",
  keyLibraryName: "TransferVerificationKey",
  prefix: "TRANSFER",
});
writeConcreteVerifier({
  source: withdraw,
  contractName: "WithdrawVerifier",
  keyLibraryName: "WithdrawVerificationKey",
  prefix: "WITHDRAW",
});
